from pydantic import BaseModel
import anthropic, json

client = anthropic.Anthropic()

class ExtractionResult(BaseModel):
    entities:  list[str]
    claims:    list[str]
    sentiment: str   # positive / negative / neutral

class AnalysisResult(BaseModel):
    main_theme:  str
    risk_level:  str   # low / medium / high
    top_entity:  str
    key_finding: str

class FinalReport(BaseModel):
    title:   str
    summary: str
    risk:    str
    action:  str

def call_tool(model_cls, user_content: str, tool_name: str):
    tool = {
        "name": tool_name,
        "description": f"Record {tool_name} results",
        "input_schema": model_cls.model_json_schema(),
    }
    resp = client.messages.create(
        model="claude-opus-4-5", max_tokens=512, temperature=0,
        tools=[tool], tool_choice={"type": "tool", "name": tool_name},
        messages=[{"role": "user", "content": user_content}],
    )
    for block in resp.content:
        if block.type == "tool_use":
            return model_cls(**block.input)
    raise RuntimeError(f"{tool_name} missing from response")

def run_chain(document: str) -> FinalReport:
    # Step 1: Extract
    step1: ExtractionResult = call_tool(ExtractionResult, document, "record_extraction")

    # Step 2: Analyze — receives only the extraction output, not the full document
    step2: AnalysisResult = call_tool(
        AnalysisResult, step1.model_dump_json(indent=2), "record_analysis"
    )

    # Step 3: Synthesize — receives both extraction and analysis
    context = json.dumps({
        "extraction": step1.model_dump(),
        "analysis": step2.model_dump(),
    }, indent=2)
    return call_tool(FinalReport, context, "record_report")

import anthropic, time
from typing import Callable, TypeVar

client = anthropic.Anthropic()
T = TypeVar("T")

def run_with_retry(fn: Callable[[], T], step_name: str, max_retries: int = 3) -> T:
    """Run a chain step with exponential back-off retry."""
    for attempt in range(1, max_retries + 1):
        try:
            return fn()
        except Exception as exc:
            if attempt == max_retries:
                raise RuntimeError(f"[{step_name}] failed after {max_retries} attempts") from exc
            wait = 0.5 * (2 ** (attempt - 1))
            print(f"[{step_name}] attempt {attempt} failed: {exc}. Retrying in {wait:.1f}s")
            time.sleep(wait)

def safe_chain(document: str) -> dict | None:
    """Run the chain; return None on unrecoverable failure."""
    # Step 1: required gate — abort entire chain if this fails
    try:
        step1 = run_with_retry(
            lambda: call_tool(ExtractionResult, document, "record_extraction"),
            "extract"
        )
    except RuntimeError as exc:
        print(f"Unrecoverable extraction failure: {exc}")
        return None   # early termination

    # Step 2: required gate
    try:
        step2 = run_with_retry(
            lambda: call_tool(AnalysisResult, step1.model_dump_json(), "record_analysis"),
            "analyze"
        )
    except RuntimeError as exc:
        print(f"Unrecoverable analysis failure: {exc}")
        return None

    # Step 3: optional — return partial result on failure rather than aborting
    try:
        step3 = run_with_retry(
            lambda: call_tool(FinalReport, step2.model_dump_json(), "record_report"),
            "synthesize",
            max_retries=2
        )
        return {"report": step3.model_dump(), "status": "complete"}
    except RuntimeError:
        return {
            "extraction": step1.model_dump(),
            "analysis": step2.model_dump(),
            "status": "partial"
        }
